import { useState, useEffect, useMemo, useCallback } from "react";
import type { Channel, Task } from "@/types";
import type { ViewType } from "@/components/tasks/ViewSwitcher";
import {
  getPinnedChannelIdsForView,
  pinChannelForRelays,
  unpinChannelFromRelays,
  type PinnedChannelsState,
} from "@/domain/preferences/pinned-channel-state";
import {
  loadPinnedChannelsState,
  savePinnedChannelsState,
} from "@/infrastructure/preferences/pinned-channels-storage";

export interface UsePinnedSidebarChannelsOptions {
  userPubkey: string | undefined;
  currentView: ViewType;
  effectiveActiveRelayIds: Set<string>;
  channels: Channel[];
  channelFilterStates: Map<string, Channel["filterState"]>;
  allTasks: Task[];
}

export interface UsePinnedSidebarChannelsResult {
  pinnedChannelsState: PinnedChannelsState;
  activeRelayIdList: string[];
  channelRelayIds: Map<string, Set<string>>;
  channelsWithState: Channel[];
  handleChannelPin: (id: string) => void;
  handleChannelUnpin: (id: string) => void;
}

export function usePinnedSidebarChannels({
  userPubkey,
  currentView,
  effectiveActiveRelayIds,
  channels,
  channelFilterStates,
  allTasks,
}: UsePinnedSidebarChannelsOptions): UsePinnedSidebarChannelsResult {
  const [pinnedChannelsState, setPinnedChannelsState] = useState<PinnedChannelsState>(
    () => loadPinnedChannelsState(userPubkey)
  );

  useEffect(() => {
    setPinnedChannelsState(loadPinnedChannelsState(userPubkey));
  }, [userPubkey]);

  useEffect(() => {
    savePinnedChannelsState(pinnedChannelsState, userPubkey);
  }, [pinnedChannelsState, userPubkey]);

  const activeRelayIdList = useMemo(
    () => Array.from(effectiveActiveRelayIds),
    [effectiveActiveRelayIds]
  );

  const channelRelayIds = useMemo(() => {
    const map = new Map<string, Set<string>>();
    for (const task of allTasks) {
      for (const tag of task.tags) {
        let relays = map.get(tag);
        if (!relays) {
          relays = new Set();
          map.set(tag, relays);
        }
        for (const relayId of task.relays) relays.add(relayId);
      }
    }
    return map;
  }, [allTasks]);

  const channelsWithState: Channel[] = useMemo(() => {
    const pinnedIds = getPinnedChannelIdsForView(
      pinnedChannelsState,
      currentView,
      activeRelayIdList
    );
    const pinnedSet = new Set(pinnedIds);
    const existingIds = new Set(channels.map((c) => c.id));
    const stubs: Channel[] = pinnedIds
      .filter((id) => !existingIds.has(id))
      .map((id) => ({ id, name: id, usageCount: 0, filterState: "neutral" as const }));
    return [...stubs, ...channels]
      .map((channel) => ({
        ...channel,
        filterState: channelFilterStates.get(channel.id) ?? "neutral",
      }))
      .sort((a, b) => {
        const aIdx = pinnedSet.has(a.id) ? pinnedIds.indexOf(a.id) : Infinity;
        const bIdx = pinnedSet.has(b.id) ? pinnedIds.indexOf(b.id) : Infinity;
        return aIdx - bIdx;
      });
  }, [
    channels,
    channelFilterStates,
    pinnedChannelsState,
    currentView,
    activeRelayIdList,
  ]);

  const handleChannelPin = useCallback(
    (id: string) => {
      const relaysWithTag = channelRelayIds.get(id);
      const targetRelayIds = relaysWithTag
        ? activeRelayIdList.filter((r) => relaysWithTag.has(r))
        : activeRelayIdList;
      const relayIds = targetRelayIds.length > 0 ? targetRelayIds : activeRelayIdList;
      setPinnedChannelsState((prev) => pinChannelForRelays(prev, currentView, relayIds, id));
    },
    [activeRelayIdList, channelRelayIds, currentView]
  );

  const handleChannelUnpin = useCallback(
    (id: string) => {
      setPinnedChannelsState((prev) =>
        unpinChannelFromRelays(prev, currentView, activeRelayIdList, id)
      );
    },
    [activeRelayIdList, currentView]
  );

  return {
    pinnedChannelsState,
    activeRelayIdList,
    channelRelayIds,
    channelsWithState,
    handleChannelPin,
    handleChannelUnpin,
  };
}

import { useCallback, useEffect, useMemo, useState } from "react";
import type { Dispatch, SetStateAction } from "react";
import type { TFunction } from "i18next";
import { toast } from "sonner";
import { getPreferredMentionIdentifier } from "@/lib/mentions";
import {
  loadPersistedChannelFilters,
  loadPersistedChannelMatchMode,
  savePersistedChannelFilters,
  savePersistedChannelMatchMode,
} from "@/infrastructure/preferences/filter-preferences-storage";
import {
  mapPeopleSelection,
  setAllChannelFilters,
  setExclusiveChannelFilter,
  shouldToggleOffExclusiveChannel,
  shouldToggleOffExclusivePerson,
} from "@/domain/content/filter-state-utils";
import {
  clampMinPriority,
  clampRecentDays,
  normalizeQuickFilterState,
} from "@/domain/content/quick-filter-constraints";
import { useFilterUrlSync } from "@/features/feed-page/controllers/use-filter-url-sync";
import { featureDebugLog } from "@/lib/feature-debug";
import type { Channel, ChannelMatchMode, Person, PostedTag, QuickFilterState, Relay } from "@/types";
import type { FeedInteractionHandlerMap } from "@/features/feed-page/interactions/feed-interaction-pipeline";

interface UseIndexFiltersOptions {
  relays: Relay[];
  setActiveRelayIds: Dispatch<SetStateAction<Set<string>>>;
  channels: Channel[];
  composeChannels: Channel[];
  setPostedTags: Dispatch<SetStateAction<PostedTag[]>>;
  people: Person[];
  setPeople: Dispatch<SetStateAction<Person[]>>;
  sidebarPeople: Person[];
  isMobile: boolean;
  hasLiveHydratedScope?: boolean;
  isHydrating?: boolean;
  setSearchQuery: Dispatch<SetStateAction<string>>;
  t: TFunction;
}

export function useIndexFilters({
  relays,
  setActiveRelayIds,
  channels,
  composeChannels,
  setPostedTags,
  people,
  setPeople,
  sidebarPeople,
  isMobile,
  hasLiveHydratedScope = false,
  isHydrating = false,
  setSearchQuery,
  t,
}: UseIndexFiltersOptions) {
  const [mentionRequest, setMentionRequest] = useState<{ mention: string; id: number } | null>(null);
  const [channelFilterStates, setChannelFilterStates] = useState<Map<string, Channel["filterState"]>>(
    () => loadPersistedChannelFilters()
  );
  const [channelMatchMode, setChannelMatchMode] = useState<ChannelMatchMode>(
    () => loadPersistedChannelMatchMode()
  );
  const [quickFilters, setQuickFilters] = useState<QuickFilterState>(() => normalizeQuickFilterState());

  const channelsWithState = useMemo(
    () =>
      channels.map((channel) => ({
        ...channel,
        filterState: channelFilterStates.get(channel.id) || "neutral",
      })),
    [channelFilterStates, channels]
  );

  const composeChannelsWithState = useMemo(
    () =>
      composeChannels.map((channel) => ({
        ...channel,
        filterState: channelFilterStates.get(channel.id) || "neutral",
      })),
    [channelFilterStates, composeChannels]
  );

  const isFilterPruneReady = hasLiveHydratedScope || !isHydrating;

  useEffect(() => {
    if (!isFilterPruneReady) return;
    const availableChannelIds = new Set([
      ...channels.map((channel) => channel.id),
      ...composeChannels
        .filter((channel) => channel.usageCount !== 0)
        .map((channel) => channel.id),
    ]);
    setChannelFilterStates((prev) => {
      let changed = false;
      const next = new Map(prev);

      for (const [id] of prev) {
        if (availableChannelIds.has(id)) continue;
        next.delete(id);
        changed = true;
      }

      return changed ? next : prev;
    });
  }, [channels, composeChannels, isFilterPruneReady]);

  useEffect(() => {
    if (!isFilterPruneReady) return;
    const sidebarPersonIds = new Set(sidebarPeople.map((person) => person.id));
    setPeople((prev) => {
      let changed = false;
      const next = prev.map((person) => {
        if (!person.isSelected || sidebarPersonIds.has(person.id)) return person;
        changed = true;
        return { ...person, isSelected: false };
      });

      return changed ? next : prev;
    });
  }, [isFilterPruneReady, setPeople, sidebarPeople]);

  useFilterUrlSync({
    channelFilterStates,
    people,
    setChannelFilterStates,
    setPeople,
  });

  useEffect(() => {
    savePersistedChannelFilters(channelFilterStates);
  }, [channelFilterStates]);

  useEffect(() => {
    savePersistedChannelMatchMode(channelMatchMode);
  }, [channelMatchMode]);

  const filterHandlers: FeedInteractionHandlerMap = useMemo(() => ({
    "sidebar.channel.toggle": (intent) => {
      setChannelFilterStates((prev) => {
        const next = new Map(prev);
        const currentState = next.get(intent.channelId) || "neutral";
        const states: Channel["filterState"][] = ["neutral", "included", "excluded"];
        const currentIndex = states.indexOf(currentState);
        next.set(intent.channelId, states[(currentIndex + 1) % states.length]);
        return next;
      });
    },
    "filter.clearChannel": (intent) => {
      setChannelFilterStates((prev) => {
        if ((prev.get(intent.channelId) || "neutral") === "neutral") return prev;
        const next = new Map(prev);
        next.set(intent.channelId, "neutral");
        return next;
      });
    },
    "sidebar.channel.exclusive": (intent) => {
      const shouldToggleOff = shouldToggleOffExclusiveChannel(channels, channelFilterStates, intent.channelId);
      if (shouldToggleOff) {
        setChannelFilterStates((prev) => {
          const next = new Map(prev);
          next.set(intent.channelId, "neutral");
          return next;
        });
        return;
      }
      setChannelFilterStates(() => setExclusiveChannelFilter(channels, intent.channelId));
      const channel = channelsWithState.find((entry) => entry.id === intent.channelId);
      toast(t("toasts.success.showingOnlyChannel", { channelName: channel?.name || intent.channelId }));
    },
    "sidebar.channel.toggleAll": () => {
      const hasActiveFilters =
        channelFilterStates.size > 0 &&
        Array.from(channelFilterStates.values()).some((state) => state !== "neutral");
      if (!hasActiveFilters) return;
      setChannelFilterStates(() => setAllChannelFilters(channels, "neutral"));
      toast(t("toasts.success.allChannelsReset"));
    },
    "sidebar.channel.matchMode.change": (intent) => {
      setChannelMatchMode(intent.mode);
    },
    "filter.applyHashtagExclusive": (intent) => {
      const normalizedTag = intent.tag.trim().toLowerCase();
      if (!normalizedTag) return;
      const existsInSidebar = channels.some((channel) => channel.name.toLowerCase() === normalizedTag);
      const scopedRelayIds = relays.filter((relay) => relay.isActive).map((relay) => relay.id);

      if (!existsInSidebar) {
        setPostedTags((prev) => {
          const next = prev.filter((entry) => entry.name !== normalizedTag);
          return [...next, { name: normalizedTag, relayIds: scopedRelayIds }];
        });
      }

      setChannelFilterStates(() => {
        const channelId = channels.find((channel) => channel.name.toLowerCase() === normalizedTag)?.id || normalizedTag;
        const allChannels = existsInSidebar
          ? channels
          : [...channels, { id: normalizedTag, name: normalizedTag, filterState: "neutral" as const }];
        return setExclusiveChannelFilter(allChannels, channelId);
      });

      toast(t("toasts.success.showingOnlyTag", { tag: normalizedTag }));
    },
    "sidebar.person.toggle": (intent) => {
      setPeople((prev) =>
        prev.map((person) =>
          person.id === intent.personId ? { ...person, isSelected: !person.isSelected } : person
        )
      );
    },
    "filter.clearPerson": (intent) => {
      setPeople((prev) =>
        prev.map((person) =>
          person.id === intent.personId && person.isSelected ? { ...person, isSelected: false } : person
        )
      );

import { render, screen } from "@testing-library/react";
import { beforeEach, describe, expect, it } from "vitest";
import { usePinnedSidebarChannels } from "./use-pinned-sidebar-channels";
import { makeChannel, makeTask } from "@/test/fixtures";
import type { Channel } from "@/types";

function Harness({
  channels,
  channelFilterStates,
}: {
  channels: Channel[];
  channelFilterStates: Map<string, Channel["filterState"]>;
}) {
  const result = usePinnedSidebarChannels({
    userPubkey: undefined,
    currentView: "feed",
    effectiveActiveRelayIds: new Set(["relay-one"]),
    channels,
    channelFilterStates,
    allTasks: [
      makeTask({ id: "task-one", tags: ["general"], relays: ["relay-one"] }),
      makeTask({ id: "task-two", tags: ["ops"], relays: ["relay-one"] }),
    ],
  });

  return (
    <output data-testid="channels-with-state">
      {result.channelsWithState
        .map((channel) => `${channel.id}:${channel.filterState}`)
        .join(",")}
    </output>
  );
}

describe("usePinnedSidebarChannels", () => {
  beforeEach(() => {
    window.localStorage.clear();
  });

  it("does not surface missing active filtered channels in the sidebar", () => {
    render(
      <Harness
        channels={[makeChannel({ id: "general", name: "general" })]}
        channelFilterStates={new Map([
          ["urgent", "included"],
        ])}
      />
    );

    expect(screen.getByTestId("channels-with-state")).toHaveTextContent("general:neutral");
    expect(screen.getByTestId("channels-with-state")).not.toHaveTextContent("urgent:included");
  });

  it("does not duplicate a channel already present in the derived list", () => {
    render(
      <Harness
        channels={[
          makeChannel({ id: "general", name: "general" }),
          makeChannel({ id: "urgent", name: "urgent" }),
        ]}
        channelFilterStates={new Map([
          ["urgent", "included"],
        ])}
      />
    );

    expect(screen.getByTestId("channels-with-state")).toHaveTextContent("general:neutral,urgent:included");
  });
});

