export type ViewPinnedEntityEntry<IdKey extends string> = {
  [K in IdKey]: string;
} & {
  pinnedAt: string;
  order: number;
};

export interface PinnedEntityState<IdKey extends string> {
  version: 2;
  updatedAt: string;
  byView: Partial<Record<string, Partial<Record<string, ViewPinnedEntityEntry<IdKey>[]>>>>;
}

export function createEmptyPinnedEntityState<IdKey extends string>(): PinnedEntityState<IdKey> {
  return { version: 2, updatedAt: "", byView: {} };
}

export function getPinnedEntityIdsForView<IdKey extends string>(
  state: PinnedEntityState<IdKey>,
  view: string,
  relayIds: string[],
  idKey: IdKey
): string[] {
  const minOrderById = new Map<string, number>();
  for (const relayId of relayIds) {
    for (const entry of state.byView[view]?.[relayId] ?? []) {
      const entityId = entry[idKey];
      const current = minOrderById.get(entityId);
      if (current === undefined || entry.order < current) {
        minOrderById.set(entityId, entry.order);
      }
    }
  }
  return Array.from(minOrderById.entries())
    .sort(([idA, orderA], [idB, orderB]) => orderA - orderB || idA.localeCompare(idB))
    .map(([id]) => id);
}

export function isPinnedEntityForAnyRelay<IdKey extends string>(
  state: PinnedEntityState<IdKey>,
  view: string,
  relayIds: string[],
  entityId: string,
  idKey: IdKey
): boolean {
  return relayIds.some((relayId) =>
    (state.byView[view]?.[relayId] ?? []).some((entry) => entry[idKey] === entityId)
  );
}

export function pinEntityForRelays<IdKey extends string>(
  state: PinnedEntityState<IdKey>,
  view: string,
  relayIds: string[],
  entityId: string,
  idKey: IdKey
): PinnedEntityState<IdKey> {
  let next = state;
  const now = new Date().toISOString();
  for (const relayId of relayIds) {
    const entries = next.byView[view]?.[relayId] ?? [];
    if (entries.some((entry) => entry[idKey] === entityId)) continue;
    const maxOrder = entries.length > 0 ? Math.max(...entries.map((entry) => entry.order)) : -1;
    const newEntry = { [idKey]: entityId, pinnedAt: now, order: maxOrder + 1 } as ViewPinnedEntityEntry<IdKey>;
    next = {
      ...next,
      updatedAt: now,
      byView: {
        ...next.byView,
        [view]: { ...next.byView[view], [relayId]: [...entries, newEntry] },
      },
    };
  }
  return next;
}

export function unpinEntityFromRelays<IdKey extends string>(
  state: PinnedEntityState<IdKey>,
  view: string,
  relayIds: string[],
  entityId: string,
  idKey: IdKey
): PinnedEntityState<IdKey> {
  let next = state;
  const now = new Date().toISOString();
  for (const relayId of relayIds) {
    const entries = next.byView[view]?.[relayId] ?? [];
    if (!entries.some((entry) => entry[idKey] === entityId)) continue;
    next = {
      ...next,
      updatedAt: now,
      byView: {
        ...next.byView,
        [view]: {
          ...next.byView[view],
          [relayId]: entries.filter((entry) => entry[idKey] !== entityId),
        },
      },
    };
  }
  return next;
}

import { z } from "zod";
import type {
  PinnedEntityState,
  ViewPinnedEntityEntry,
} from "@/domain/preferences/pinned-entity-state";

function buildPinnedEntityStateSchema(idKey: string) {
  const entryShape: z.ZodRawShape = {
    pinnedAt: z.string(),
    order: z.number().finite(),
  };
  entryShape[idKey] = z.string();

  return z.object({
    version: z.literal(2),
    updatedAt: z.string(),
    byView: z.record(
      z.string(),
      z.record(z.string(), z.array(z.object(entryShape)).optional()).optional()
    ),
  });
}

function storageKey(namespace: string, pubkey?: string): string {
  const prefix = pubkey ? pubkey.slice(0, 8) : "guest";
  return `nodex.${namespace}.${prefix}.v2`;
}

function stripInvalidEntries<IdKey extends string>(
  rawState: PinnedEntityState<IdKey>,
  idKey: IdKey
): PinnedEntityState<IdKey>["byView"] {
  const byView: PinnedEntityState<IdKey>["byView"] = {};
  for (const [view, byRelay] of Object.entries(rawState.byView)) {
    if (!byRelay) continue;
    const cleanedByRelay: Partial<Record<string, ViewPinnedEntityEntry<IdKey>[]>> = {};
    for (const [relayId, entries] of Object.entries(byRelay)) {
      if (!entries) continue;
      const valid = entries.filter((entry) => entry[idKey].trim() !== "");
      if (valid.length > 0) cleanedByRelay[relayId] = valid;
    }
    if (Object.keys(cleanedByRelay).length > 0) byView[view] = cleanedByRelay;
  }
  return byView;
}

export function loadPinnedEntityState<IdKey extends string>(params: {
  namespace: string;
  idKey: IdKey;
  pubkey?: string;
  createEmptyState: () => PinnedEntityState<IdKey>;
}): PinnedEntityState<IdKey> {
  const { namespace, idKey, pubkey, createEmptyState } = params;
  try {
    const raw = localStorage.getItem(storageKey(namespace, pubkey));
    if (!raw) return createEmptyState();
    const parsed = buildPinnedEntityStateSchema(idKey).safeParse(JSON.parse(raw));
    if (!parsed.success) return createEmptyState();
    const validData = parsed.data as PinnedEntityState<IdKey>;
    return {
      version: 2,
      updatedAt: validData.updatedAt,
      byView: stripInvalidEntries(validData, idKey),
    };
  } catch {
    return createEmptyState();
  }
}

export function savePinnedEntityState<IdKey extends string>(params: {
  namespace: string;
  state: PinnedEntityState<IdKey>;
  pubkey?: string;
}): void {
  const { namespace, state, pubkey } = params;
  try {
    localStorage.setItem(storageKey(namespace, pubkey), JSON.stringify(state));
  } catch {
    // Ignore storage failures and keep runtime behavior intact.
  }
}

import { beforeEach, describe, expect, it } from "vitest";
import {
  createEmptyPinnedChannelsState,
  getPinnedChannelIdsForView,
  pinChannelForRelays,
  type PinnedChannelsState,
} from "@/domain/preferences/pinned-channel-state";
import {
  loadPinnedChannelsState,
  savePinnedChannelsState,
} from "./pinned-channels-storage";

const RELAY_A = "relay-a";

beforeEach(() => {
  localStorage.clear();
});

describe("loadPinnedChannelsState", () => {
  it("returns empty state when localStorage is empty", () => {
    expect(loadPinnedChannelsState()).toEqual(createEmptyPinnedChannelsState());
  });

  it("returns empty state on corrupt JSON", () => {
    localStorage.setItem("nodex.pinned-channels.guest.v2", "not-json{{{");
    expect(loadPinnedChannelsState()).toEqual(createEmptyPinnedChannelsState());
  });

  it("strips entries with empty channel ids", () => {
    const raw: PinnedChannelsState = {
      version: 2,
      updatedAt: "",
      byView: {
        feed: {
          [RELAY_A]: [
            { channelId: "valid", pinnedAt: "2026-01-01T00:00:00.000Z", order: 0 },
            { channelId: "", pinnedAt: "2026-01-01T00:00:00.000Z", order: 1 },
          ],
        },
      },
    };
    localStorage.setItem("nodex.pinned-channels.guest.v2", JSON.stringify(raw));
    const state = loadPinnedChannelsState();
    expect(getPinnedChannelIdsForView(state, "feed", [RELAY_A])).toEqual(["valid"]);
  });

  it("uses the pubkey prefix as part of the storage key", () => {
    const pubkey = "abcdef1234567890";
    const raw: PinnedChannelsState = {
      version: 2,
      updatedAt: "",
      byView: {
        feed: {
          [RELAY_A]: [{ channelId: "work", pinnedAt: "2026-01-01T00:00:00.000Z", order: 0 }],
        },
      },
    };
    localStorage.setItem("nodex.pinned-channels.abcdef12.v2", JSON.stringify(raw));
    expect(getPinnedChannelIdsForView(loadPinnedChannelsState(pubkey), "feed", [RELAY_A])).toEqual([
      "work",
    ]);
  });
});

describe("savePinnedChannelsState", () => {
  it("round-trips persisted state", () => {
    const state = pinChannelForRelays(createEmptyPinnedChannelsState(), "feed", [RELAY_A], "work");
    savePinnedChannelsState(state);
    expect(getPinnedChannelIdsForView(loadPinnedChannelsState(), "feed", [RELAY_A])).toEqual([
      "work",
    ]);
  });
});

