      ...next,
      updatedAt: now,
      byRelay: {
        ...next.byRelay,
        [relayId]: [...entries, newEntry],
      },
    };
  }
  return next;
}

export function unpinChannelFromRelays(
  state: PinnedChannelsState,
  relayIds: string[],
  channelId: string
): PinnedChannelsState {
  let next = state;
  const now = new Date().toISOString();
  for (const relayId of relayIds) {
